INSERT INTO "UXInstrument" (instrument_id, name, version, description, reference_url)
INSERT INTO "Item" (item_id, instrument_id, item_number, subscale, text) VALUES
  ('899dc1c7-ef54-47ad-a7a1-da34d15b681d', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 1, 'autonomy', 'Me sentí libre de jugar el juego como yo quería'),
  ('4176cdf1-11fb-469d-9d26-63adb60f23d3', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 2, 'autonomy', 'Sentí que mis elecciones en el juego reflejaban mis propios deseos e intereses'),
  ('777ad36b-e60f-407e-a9ad-e7c7840518c3', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 3, 'autonomy', 'Tuve la oportunidad de tomar decisiones significativas sobre cómo progresar'),
  ('6ae8c1b1-b154-4864-bf61-d5c9cff51886', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 4, 'autonomy', 'A menudo me sentí obligado a jugar de cierta manera'),
  ('9c13a50e-d809-4587-9d2f-5e2cb047f224', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 5, 'autonomy', 'Sentí que el juego limitaba mi libertad innecesariamente'),
  ('1d69d618-f55e-4ee4-8bfc-e6dc104d3f95', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 6, 'autonomy', 'A menudo me encontré haciendo cosas que realmente no quería hacer en el juego'),
  ('1715d39c-d40e-4f0e-b56e-ce0652c6a5c0', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 7, 'competence', 'Sentí que podía dominar los retos de este juego'),
  ('437b936d-3d15-4316-a3e0-f93c10252597', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 8, 'competence', 'Sentí una sensación de logro al jugar'),
  ('60930690-4370-4f97-9062-f4235683bcfc', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 9, 'competence', 'Sentí que era capaz de superar los obstáculos del juego'),
  ('e52f11e8-d134-4c13-8396-fc6003fae1f5', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 10, 'competence', 'Sentí que el juego era demasiado difícil y me frustraba'),
  ('7ec93f8d-0215-4c02-b322-408e1c9760ef', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 11, 'competence', 'A menudo me sentí incompetente o incapaz de jugar bien'),
  ('97fc7d4d-434c-44f9-aa92-d0195aa02c01', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 12, 'competence', 'Sentí que mis esfuerzos eran inútiles para lograr mis objetivos'),
  ('528ffa83-a0cb-456a-9cb5-dfaad6f9e387', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 13, 'relatedness', 'Sentí una fuerte conexión con otros jugadores o personajes'),
  ('5a236670-6e9b-4c9a-9ac1-9526a647f915', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 14, 'relatedness', 'Sentí que me importaban y me valoraban dentro del entorno del juego'),
  ('38a05da4-68d0-4ebf-81d5-7cdec4cbfd33', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 15, 'relatedness', 'Sentí que formaba parte de una comunidad o equipo'),
  ('4fdd55c6-81b4-4caa-85d3-448d87bdc8ce', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 16, 'relatedness', 'Sentí que los demás jugadores/personajes me ignoraban o excluían'),
  ('a229695e-3689-4553-814c-8068a179f00f', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 17, 'relatedness', 'Sentí una desconexión emocional con el mundo del juego y sus personajes'),
  ('81440e05-efc2-4973-9733-4367c9fdd2bf', 'a129efda-dd02-4992-aa0e-c00b1314ea26', 18, 'relatedness', 'Sentí que mis interacciones con otros jugadores o personajes eran superficiales o frustrantes');
